create table maxprint_dev.simple_purchase (
    id                       number generated by default on null as identity not null enable,
    name                     varchar2(100 byte),
    creation                 timestamp(9),
    modified                 timestamp(9),
    modified_by              varchar2(50 byte),
    owner                    varchar2(50 byte),
    docstatus                number,
    idx                      number,
    party_type               varchar2(50 byte),
    party                    varchar2(255 byte),
    payment_method           varchar2(50 byte),
    payment_account          varchar2(50 byte),
    currency                 varchar2(50 byte),
    ex_rate                  number,
    remarks                  varchar2(4000 byte),
    naming_series            varchar2(50 byte),
    company                  varchar2(50 byte),
    payment_date             date,
    posting_date             date,
    ref_no                   number,
    ref_date                 varchar2(4000 byte),
    letter_head              varchar2(50 byte),
    total                    number,
    total_pkr                number,
    amended_from             varchar2(50 byte),
    c_user_tags              varchar2(4000 byte),
    c_comments               varchar2(4000 byte),
    c_assign                 varchar2(4000 byte),
    c_liked_by               varchar2(4000 byte),
    custom_recurring_expense number
);

alter table maxprint_dev.simple_purchase add primary key ( id )
    using index enable;


